previewCss:
.darma-loader-uiverse-aqua-pill-fill {
  /* color of choise */
  --clr: #05A8AA;
  /* loading time of choice */
  --load-time: 2s;
  outline: 5px solid var(--clr);
  outline-offset: 5px;
  position: relative;
  overflow: hidden;
  border-radius: 5rem;
  /* width: 10rem; */
  /* height: 2rem; */
  padding: 1rem 5rem;
  /* use either padding or width + height*/
  /* I prefer the padding one */
  /* rotate: -90deg; */
  /* rotate if you want/need vertical loader */
}

.darma-loader-uiverse-aqua-pill-fill::after {
content: '';
position: absolute;
top: 0;
left: 0;
width: 100%;
height: 100%;
background-color: var(--clr);
z-index: 2;
animation: darma-loader-uiverse-aqua-pill-fill-loading var(--load-time) ease-in-out infinite;
}

@keyframes darma-loader-uiverse-aqua-pill-fill-loading {
0% {
width: 0%;
}

100% {
width: 100%;
}
}

